#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, A, B; scanf("%d %d %d", &N, &A, &B);
        int a = A < B ? A : B;
        int b = A < B ? B : A;
        int d = b - a;
        int ans = 0;
        if (d == 1) {
            if (a - 1 >= 1) ans++;
            if (a + 2 <= N) ans++;
        } else if (d == 2) {
            ans = 1;
        }
        // d==0 or d>2 => ans stays 0
        printf("%d\n", ans);
    }
    return 0;
}

