            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int A = Integer.parseInt(st.nextToken());
            int B = Integer.parseInt(st.nextToken());
            int a = Math.min(A, B);
            int b = Math.max(A, B);
            int d = b - a;
            int ans = 0;
            if (d == 1) {
                if (a - 1 >= 1) ans++;
                if (a + 2 <= N) ans++;
            } else if (d == 2) {
                ans = 1;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

