#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); A = int(next(it)); B = int(next(it))
        a, b = (A, B) if A < B else (B, A)
        d = b - a
        ans = 0
        if d == 1:
            if a - 1 >= 1:
                ans += 1
            if a + 2 <= N:
                ans += 1
        elif d == 2:
            ans = 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

